package agent

import (
	"strings"
	"time"
)

// UsageWindowCounts is a rolling-window usage summary for one endpoint/harness,
// computed from SessionIndexEntry rows. A zero value indicates a window that
// was requested but contained no matching entries — callers decide whether to
// render "0" or "not reported".
type UsageWindowCounts struct {
	TokensLastHour   int
	TokensLast24h    int
	RequestsLastHour int
	RequestsLast24h  int
}

// UsageMatchKind selects which session field identifies the row.
type UsageMatchKind int

const (
	// MatchProvider matches SessionIndexEntry.Provider (endpoint providers).
	MatchProvider UsageMatchKind = iota
	// MatchHarness matches SessionIndexEntry.Harness (subprocess harnesses).
	MatchHarness
)

// AggregateUsageCounts walks a sorted-newest-first slice of SessionIndexEntry
// and returns rolling-window totals for the given name. Matching is
// case-insensitive; empty name returns a zero struct.
func AggregateUsageCounts(entries []SessionIndexEntry, name string, kind UsageMatchKind, now time.Time) UsageWindowCounts {
	name = strings.TrimSpace(strings.ToLower(name))
	if name == "" {
		return UsageWindowCounts{}
	}
	if now.IsZero() {
		now = time.Now().UTC()
	}
	var out UsageWindowCounts
	cutoffHour := now.Add(-time.Hour)
	cutoff24h := now.Add(-24 * time.Hour)
	for _, e := range entries {
		if !matchesUsageName(e, name, kind) {
			continue
		}
		if e.StartedAt.Before(cutoff24h) {
			continue
		}
		tokens := sessionTokens(e)
		out.TokensLast24h += tokens
		out.RequestsLast24h++
		if !e.StartedAt.Before(cutoffHour) {
			out.TokensLastHour += tokens
			out.RequestsLastHour++
		}
	}
	return out
}

func matchesUsageName(e SessionIndexEntry, lowerName string, kind UsageMatchKind) bool {
	switch kind {
	case MatchProvider:
		return strings.ToLower(strings.TrimSpace(e.Provider)) == lowerName
	case MatchHarness:
		return strings.ToLower(strings.TrimSpace(e.Harness)) == lowerName
	}
	return false
}

func sessionTokens(e SessionIndexEntry) int {
	if e.Tokens > 0 {
		return e.Tokens
	}
	return e.InputTokens + e.OutputTokens
}

// UsageBucket is one time-bucketed aggregate: tokens and request count.
type UsageBucket struct {
	Start    time.Time
	Tokens   int
	Requests int
}

// BucketUsage returns equally-spaced buckets covering the windowDays, aligned
// to `bucketSize`, in ascending order. Buckets with no sessions are emitted as
// zero counts so the series is dense for charts.
func BucketUsage(entries []SessionIndexEntry, name string, kind UsageMatchKind, now time.Time, windowDays int, bucketSize time.Duration) []UsageBucket {
	if windowDays <= 0 {
		return nil
	}
	if bucketSize <= 0 {
		bucketSize = time.Hour
	}
	name = strings.TrimSpace(strings.ToLower(name))
	if name == "" {
		return nil
	}
	if now.IsZero() {
		now = time.Now().UTC()
	}
	end := truncateToBucket(now, bucketSize).Add(bucketSize)
	start := end.Add(-time.Duration(windowDays) * 24 * time.Hour)
	bucketCount := int(end.Sub(start) / bucketSize)
	if bucketCount <= 0 {
		return nil
	}
	buckets := make([]UsageBucket, bucketCount)
	for i := range buckets {
		buckets[i].Start = start.Add(time.Duration(i) * bucketSize)
	}
	for _, e := range entries {
		if !matchesUsageName(e, name, kind) {
			continue
		}
		if e.StartedAt.Before(start) || !e.StartedAt.Before(end) {
			continue
		}
		idx := int(e.StartedAt.Sub(start) / bucketSize)
		if idx < 0 || idx >= bucketCount {
			continue
		}
		buckets[idx].Tokens += sessionTokens(e)
		buckets[idx].Requests++
	}
	return buckets
}

func truncateToBucket(t time.Time, d time.Duration) time.Time {
	t = t.UTC()
	if d <= 0 {
		return t
	}
	return t.Truncate(d)
}

// LinearSlope returns the least-squares slope (units per bucket) of a series
// of observations, or 0 when the series is too small to compute.
func LinearSlope(values []float64) float64 {
	n := len(values)
	if n < 2 {
		return 0
	}
	var sumX, sumY, sumXY, sumXX float64
	for i, y := range values {
		x := float64(i)
		sumX += x
		sumY += y
		sumXY += x * y
		sumXX += x * x
	}
	fn := float64(n)
	denom := fn*sumXX - sumX*sumX
	if denom == 0 {
		return 0
	}
	return (fn*sumXY - sumX*sumY) / denom
}

package agent

import (
	"fmt"
	"testing"
	"time"
)

func fixedNow() time.Time {
	return time.Date(2026, 4, 23, 12, 0, 0, 0, time.UTC)
}

func makeUsageEntry(started time.Time, provider, harness string, tokens int) SessionIndexEntry {
	return SessionIndexEntry{
		StartedAt: started,
		Provider:  provider,
		Harness:   harness,
		Tokens:    tokens,
	}
}

func TestAggregateUsageCounts_ProviderWindow(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeUsageEntry(now.Add(-30*time.Minute), "qwen", "agent", 100),
		makeUsageEntry(now.Add(-2*time.Hour), "qwen", "agent", 200),
		makeUsageEntry(now.Add(-25*time.Hour), "qwen", "agent", 999), // outside 24h
		makeUsageEntry(now.Add(-30*time.Minute), "other", "agent", 50),
	}
	c := AggregateUsageCounts(entries, "qwen", MatchProvider, now)
	if c.TokensLastHour != 100 {
		t.Errorf("tokens last hour: got %d want 100", c.TokensLastHour)
	}
	if c.TokensLast24h != 300 {
		t.Errorf("tokens last 24h: got %d want 300", c.TokensLast24h)
	}
	if c.RequestsLastHour != 1 {
		t.Errorf("requests last hour: got %d want 1", c.RequestsLastHour)
	}
	if c.RequestsLast24h != 2 {
		t.Errorf("requests last 24h: got %d want 2", c.RequestsLast24h)
	}
}

func TestAggregateUsageCounts_HarnessWindow(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeUsageEntry(now.Add(-15*time.Minute), "", "claude", 500),
		makeUsageEntry(now.Add(-5*time.Hour), "", "claude", 800),
		makeUsageEntry(now.Add(-15*time.Minute), "", "codex", 100),
	}
	c := AggregateUsageCounts(entries, "claude", MatchHarness, now)
	if c.TokensLastHour != 500 || c.TokensLast24h != 1300 {
		t.Errorf("claude aggregate mismatch: %+v", c)
	}
}

func TestAggregateUsageCounts_FallBackToInputOutput(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		{StartedAt: now.Add(-30 * time.Minute), Harness: "claude", InputTokens: 400, OutputTokens: 100},
	}
	c := AggregateUsageCounts(entries, "claude", MatchHarness, now)
	if c.TokensLastHour != 500 {
		t.Errorf("fallback sum tokens: got %d want 500", c.TokensLastHour)
	}
}

func TestAggregateUsageCounts_CaseInsensitive(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		{StartedAt: now.Add(-1 * time.Minute), Harness: "CLAUDE", Tokens: 42},
	}
	c := AggregateUsageCounts(entries, "claude", MatchHarness, now)
	if c.TokensLastHour != 42 {
		t.Errorf("case-insensitive match: %+v", c)
	}
}

func TestBucketUsage_HourlyBuckets(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeUsageEntry(now.Add(-30*time.Minute), "qwen", "", 100),
		makeUsageEntry(now.Add(-90*time.Minute), "qwen", "", 50),
		makeUsageEntry(now.Add(-30*time.Minute), "other", "", 10),
	}
	buckets := BucketUsage(entries, "qwen", MatchProvider, now, 1, time.Hour)
	if len(buckets) != 24 {
		t.Fatalf("expected 24 hourly buckets over 1 day, got %d", len(buckets))
	}
	var total int
	for _, b := range buckets {
		total += b.Tokens
	}
	if total != 150 {
		t.Errorf("total across buckets: got %d want 150", total)
	}
	// Ordering ascending
	for i := 1; i < len(buckets); i++ {
		if !buckets[i].Start.After(buckets[i-1].Start) {
			t.Errorf("buckets not ascending at %d", i)
		}
	}
}

func TestBucketUsage_4HourBuckets(t *testing.T) {
	now := fixedNow()
	entries := []SessionIndexEntry{
		makeUsageEntry(now.Add(-1*time.Hour), "qwen", "", 10),
		makeUsageEntry(now.Add(-5*time.Hour), "qwen", "", 20),
	}
	buckets := BucketUsage(entries, "qwen", MatchProvider, now, 2, 4*time.Hour)
	if len(buckets) != 12 {
		t.Fatalf("expected 12 4h buckets over 2 days, got %d", len(buckets))
	}
}

func TestLinearSlope(t *testing.T) {
	// Ascending series: slope should be positive.
	if s := LinearSlope([]float64{10, 20, 30, 40}); s != 10 {
		t.Errorf("perfect line slope: got %f want 10", s)
	}
	// Flat series: slope 0.
	if s := LinearSlope([]float64{5, 5, 5, 5}); s != 0 {
		t.Errorf("flat slope: got %f want 0", s)
	}
	// Too short.
	if s := LinearSlope([]float64{42}); s != 0 {
		t.Errorf("single point slope: got %f want 0", s)
	}
}

func TestAggregateUsageCounts_PerfOneThousandRows(t *testing.T) {
	// Per standing directive in ddx-9ce6842a: fixture of ≥1k session rows
	// covering last 24h; aggregation must return correct counts and stay
	// well under the 200ms HTTP budget.
	now := fixedNow()
	entries := make([]SessionIndexEntry, 0, 1000)
	for i := 0; i < 1000; i++ {
		minutes := time.Duration(i) * time.Minute
		entries = append(entries, SessionIndexEntry{
			StartedAt: now.Add(-minutes),
			Provider:  fmt.Sprintf("p%d", i%5),
			Harness:   fmt.Sprintf("h%d", i%5),
			Tokens:    10,
		})
	}
	start := time.Now()
	c := AggregateUsageCounts(entries, "p0", MatchProvider, now)
	elapsed := time.Since(start)
	// 200 sessions per provider per 1000/5 over ~17 hours → 60 in the last hour, 200 in last 24h.
	if c.RequestsLast24h != 200 {
		t.Errorf("expected 200 requests in 24h for p0, got %d", c.RequestsLast24h)
	}
	if c.TokensLast24h != 2000 {
		t.Errorf("expected 2000 tokens, got %d", c.TokensLast24h)
	}
	if elapsed > 50*time.Millisecond {
		t.Errorf("aggregation too slow on 1k fixture: %v (budget 50ms)", elapsed)
	}
}

package agent

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// writeSessionsJSONL writes SessionEntry values to a temp sessions.jsonl and returns its path.
func writeSessionsJSONL(t *testing.T, entries []SessionEntry) string {
	t.Helper()
	dir := t.TempDir()
	path := filepath.Join(dir, "sessions.jsonl")
	f, err := os.Create(path)
	require.NoError(t, err)
	defer f.Close()
	enc := json.NewEncoder(f)
	for _, e := range entries {
		require.NoError(t, enc.Encode(e))
	}
	return path
}

// makeEntry is a helper to build a SessionEntry for tests.
func makeEntry(id, harness, model string, ts time.Time, inputTok, outputTok int, costUSD float64, durMS int) SessionEntry {
	return SessionEntry{
		ID:           id,
		Timestamp:    ts,
		Harness:      harness,
		Model:        model,
		InputTokens:  inputTok,
		OutputTokens: outputTok,
		CostUSD:      costUSD,
		Duration:     durMS,
	}
}

// aggregateFromFile is a thin wrapper that mirrors the cmd-layer aggregation so tests
// can live in the agent package.
func aggregateFromFile(logFile, harnessFilter string, since time.Time) (map[string]struct {
	Sessions     int
	InputTokens  int
	OutputTokens int
	CostUSD      float64
}, error) {
	// Re-implement a minimal version here so the internal package can test without
	// importing cmd (which would create a cycle).
	type agg struct {
		sessions     int
		inputTokens  int
		outputTokens int
		costUSD      float64
	}

	f, err := os.Open(logFile)
	if err != nil {
		return nil, err
	}
	defer f.Close()

	result := map[string]struct {
		Sessions     int
		InputTokens  int
		OutputTokens int
		CostUSD      float64
	}{}

	dec := json.NewDecoder(f)
	for dec.More() {
		var entry SessionEntry
		if err := dec.Decode(&entry); err != nil {
			continue
		}
		if entry.Timestamp.Before(since) {
			continue
		}
		if harnessFilter != "" && entry.Harness != harnessFilter {
			continue
		}
		a := result[entry.Harness]
		a.Sessions++
		a.InputTokens += entry.InputTokens
		a.OutputTokens += entry.OutputTokens
		if entry.CostUSD > 0 {
			a.CostUSD += entry.CostUSD
		} else if entry.Model != "" {
			if est := EstimateCost(entry.Model, entry.InputTokens, entry.OutputTokens); est >= 0 {
				a.CostUSD += est
			}
		}
		result[entry.Harness] = a
	}
	return result, nil
}

// TC-006: 3 codex and 2 claude sessions → correct per-harness counts and totals.
func TestTC006_UsageAggregation(t *testing.T) {
	now := time.Now().UTC()
	entries := []SessionEntry{
		makeEntry("s1", "codex", "gpt-5.4", now, 10000, 1000, 0, 30000),
		makeEntry("s2", "codex", "gpt-5.4", now, 20000, 2000, 0, 40000),
		makeEntry("s3", "codex", "gpt-5.4", now, 30000, 3000, 0, 50000),
		makeEntry("s4", "claude", "claude-sonnet-4-6", now, 50000, 4000, 0, 35000),
		makeEntry("s5", "claude", "claude-sonnet-4-6", now, 60000, 5000, 0, 45000),
	}
	path := writeSessionsJSONL(t, entries)
	since := now.Add(-time.Hour)

	agg, err := aggregateFromFile(path, "", since)
	require.NoError(t, err)

	require.Contains(t, agg, "codex")
	require.Contains(t, agg, "claude")

	assert.Equal(t, 3, agg["codex"].Sessions)
	assert.Equal(t, 60000, agg["codex"].InputTokens)
	assert.Equal(t, 6000, agg["codex"].OutputTokens)

	assert.Equal(t, 2, agg["claude"].Sessions)
	assert.Equal(t, 110000, agg["claude"].InputTokens)
	assert.Equal(t, 9000, agg["claude"].OutputTokens)

	// Total sessions across harnesses
	total := 0
	for _, a := range agg {
		total += a.Sessions
	}
	assert.Equal(t, 5, total)
}

// TC-007: Sessions spanning multiple days; filter with since=today returns only today's.
func TestTC007_SinceToday(t *testing.T) {
	today := time.Date(2026, 4, 10, 0, 0, 0, 0, time.UTC)
	now := today.Add(12 * time.Hour)
	yesterday := today.Add(-24 * time.Hour)

	entries := []SessionEntry{
		makeEntry("old1", "codex", "gpt-5.4", yesterday.Add(-time.Hour), 1000, 100, 0, 10000),
		makeEntry("old2", "codex", "gpt-5.4", yesterday, 2000, 200, 0, 10000),
		makeEntry("new1", "codex", "gpt-5.4", now, 3000, 300, 0, 10000),
		makeEntry("new2", "claude", "claude-sonnet-4-6", now.Add(-time.Minute), 4000, 400, 0, 10000),
	}
	path := writeSessionsJSONL(t, entries)

	agg, err := aggregateFromFile(path, "", today)
	require.NoError(t, err)

	total := 0
	for _, a := range agg {
		total += a.Sessions
	}
	assert.Equal(t, 2, total, "only today's sessions should be counted")
}

// TC-008: Filter by --harness claude returns only claude sessions.
func TestTC008_HarnessFilter(t *testing.T) {
	now := time.Now().UTC()
	entries := []SessionEntry{
		makeEntry("c1", "codex", "gpt-5.4", now, 5000, 500, 0, 10000),
		makeEntry("c2", "codex", "gpt-5.4", now, 5000, 500, 0, 10000),
		makeEntry("cl1", "claude", "claude-sonnet-4-6", now, 8000, 800, 0, 20000),
	}
	path := writeSessionsJSONL(t, entries)
	since := now.Add(-time.Hour)

	agg, err := aggregateFromFile(path, "claude", since)
	require.NoError(t, err)

	assert.NotContains(t, agg, "codex", "codex should be filtered out")
	require.Contains(t, agg, "claude")
	assert.Equal(t, 1, agg["claude"].Sessions)
}

// TC-009: Cost estimation from pricing table for a codex session with known model.
func TestTC009_CostEstimation(t *testing.T) {
	now := time.Now().UTC()
	// gpt-5.4: $2.00/1M input, $8.00/1M output
	// 1,000,000 input + 1,000,000 output = $10.00
	entries := []SessionEntry{
		makeEntry("x1", "codex", "gpt-5.4", now, 1_000_000, 1_000_000, 0, 30000),
	}
	path := writeSessionsJSONL(t, entries)
	since := now.Add(-time.Hour)

	agg, err := aggregateFromFile(path, "", since)
	require.NoError(t, err)

	require.Contains(t, agg, "codex")
	expected := 2.00 + 8.00 // $10.00
	assert.InDelta(t, expected, agg["codex"].CostUSD, 0.001)
}

// TestEstimateCostKnownModel verifies the pricing function directly.
func TestEstimateCostKnownModel(t *testing.T) {
	cost := EstimateCost("gpt-5.4", 1_000_000, 1_000_000)
	assert.InDelta(t, 10.00, cost, 0.001)
}

// TestEstimateCostUnknownModel returns -1 for unknown models.
func TestEstimateCostUnknownModel(t *testing.T) {
	assert.Equal(t, -1.0, EstimateCost("unknown-model-xyz", 1000, 1000))
}

package agent

import (
	"bufio"
	"bytes"
	"crypto/sha256"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

const (
	SessionIndexDirName      = "sessions"
	LegacySessionsFileName   = "sessions.jsonl"
	LegacySessionsRenameName = "sessions.jsonl.legacy"
)

// SessionIndexEntry is the pointer-only session index row. Heavy prompt,
// response, and stderr bodies stay in execution bundles or native logs.
type SessionIndexEntry struct {
	ID              string    `json:"id"`
	ProjectID       string    `json:"projectID,omitempty"`
	BeadID          string    `json:"beadID,omitempty"`
	WorkerID        string    `json:"workerID,omitempty"`
	Harness         string    `json:"harness"`
	Provider        string    `json:"provider,omitempty"`
	Surface         string    `json:"surface,omitempty"`
	BaseURL         string    `json:"baseURL,omitempty"`
	BillingMode     string    `json:"billingMode"`
	Model           string    `json:"model,omitempty"`
	StartedAt       time.Time `json:"startedAt"`
	EndedAt         time.Time `json:"endedAt,omitempty"`
	DurationMS      int       `json:"durationMs,omitempty"`
	CostUSD         float64   `json:"cost,omitempty"`
	CostPresent     bool      `json:"costPresent,omitempty"`
	Tokens          int       `json:"tokens,omitempty"`
	InputTokens     int       `json:"inputTokens,omitempty"`
	CachedTokens    int       `json:"cachedTokens,omitempty"`
	OutputTokens    int       `json:"outputTokens,omitempty"`
	Outcome         string    `json:"outcome,omitempty"`
	ExitCode        int       `json:"exitCode"`
	NativeSessionID string    `json:"nativeSessionID,omitempty"`
	TraceID         string    `json:"traceID,omitempty"`
	SpanID          string    `json:"spanID,omitempty"`
	BundlePath      string    `json:"bundlePath,omitempty"`
	NativeLogRef    string    `json:"nativeLogRef,omitempty"`
	Effort          string    `json:"effort,omitempty"`
	Detail          string    `json:"detail,omitempty"`
	BaseRev         string    `json:"baseRev,omitempty"`
	ResultRev       string    `json:"resultRev,omitempty"`
	// ToolCalls is the normalized stream of tool_call/tool_result pairs
	// captured at drain time (Story 16). Persisting here means resolver-time
	// reads do not have to parse raw native logs.
	ToolCalls []ToolCallEntry `json:"toolCalls,omitempty"`
}

type SessionIndexQuery struct {
	StartedAfter  *time.Time
	StartedBefore *time.Time
	DefaultRecent bool
}

type SessionBodies struct {
	Prompt   string
	Response string
	Stderr   string
}

func SessionIndexDir(logDir string) string {
	return filepath.Join(logDir, SessionIndexDirName)
}

func SessionIndexShardName(t time.Time) string {
	if t.IsZero() {
		t = time.Now().UTC()
	}
	return fmt.Sprintf("sessions-%04d-%02d.jsonl", t.UTC().Year(), t.UTC().Month())
}

func SessionIndexShardPath(logDir string, t time.Time) string {
	return filepath.Join(SessionIndexDir(logDir), SessionIndexShardName(t))
}

func ProjectIDForPath(path string) string {
	canonical, err := filepath.Abs(path)
	if err == nil {
		path = canonical
	}
	h := sha256.Sum256([]byte(path))
	return fmt.Sprintf("proj-%x", h[:4])
}

func AppendSessionIndex(logDir string, entry SessionIndexEntry, now time.Time) error {
	if logDir == "" {
		return nil
	}
	if now.IsZero() {
		now = time.Now().UTC()
	}
	if entry.ID == "" {
		entry.ID = genSessionID()
	}
	if entry.StartedAt.IsZero() {
		entry.StartedAt = now.UTC()
	}
	if entry.EndedAt.IsZero() && entry.DurationMS > 0 {
		entry.EndedAt = entry.StartedAt.Add(time.Duration(entry.DurationMS) * time.Millisecond).UTC()
	}
	if entry.Outcome == "" {
		if entry.ExitCode == 0 && entry.Detail == "" {
			entry.Outcome = "success"
		} else {
			entry.Outcome = "failure"
		}
	}
	if entry.BillingMode == "" {
		entry.BillingMode = billingModeFor(entry.Harness, entry.Surface, entry.BaseURL)
	}
	if !ValidateBillingMode(entry.BillingMode) {
		return fmt.Errorf("invalid billingMode %q", entry.BillingMode)
	}
	if err := os.MkdirAll(SessionIndexDir(logDir), 0o755); err != nil {
		return err
	}
	data, err := json.Marshal(entry)
	if err != nil {
		return err
	}
	path := SessionIndexShardPath(logDir, now.UTC())
	f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return err
	}
	defer f.Close()
	_, err = fmt.Fprintf(f, "%s\n", data)
	return err
}

// SessionIndexInputs carries the small subset of RunArgs fields that
// SessionIndexEntryFromResult needs, decoupling it from the full RunArgs
// surface.
type SessionIndexInputs struct {
	Harness     string
	Model       string
	Provider    string
	Effort      string
	Correlation map[string]string
}

func SessionIndexEntryFromResult(projectRoot string, inputs SessionIndexInputs, result *Result, startedAt, endedAt time.Time) SessionIndexEntry {
	if result == nil {
		result = &Result{}
	}
	corr := inputs.Correlation
	id := ""
	beadID := ""
	workerID := ""
	bundlePath := ""
	baseRev := ""
	nativeLogRef := ""
	nativeSessionID := ""
	traceID := ""
	spanID := ""
	if corr != nil {
		id = corr["session_id"]
		beadID = corr["bead_id"]
		workerID = corr["worker_id"]
		bundlePath = corr["bundle_path"]
		baseRev = corr["base_rev"]
		nativeLogRef = corr["native_log_ref"]
		nativeSessionID = corr["native_session_id"]
		traceID = corr["trace_id"]
		spanID = corr["span_id"]
	}
	if id == "" {
		id = genSessionID()
	}
