483	func buildUsage(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) *ProviderUsage {
484		counts := agent.AggregateUsageCounts(entries, name, kind, now)
485		// FEAT-014 no-fabrication: when the session index has no rows attributable
486		// to this name, return nil so the UI renders "not reported" instead of
487		// fabricated "0 / 0" counts.
488		if counts.TokensLastHour == 0 && counts.TokensLast24h == 0 &&
489			counts.RequestsLastHour == 0 && counts.RequestsLast24h == 0 {
490			return nil
491		}
492		u := &ProviderUsage{}
493		v := counts.TokensLastHour
494		u.TokensUsedLastHour = &v
495		v2 := counts.TokensLast24h
496		u.TokensUsedLast24h = &v2
497		v3 := counts.RequestsLastHour
498		u.RequestsLastHour = &v3
499		v4 := counts.RequestsLast24h
500		u.RequestsLast24h = &v4
501		return u
502	}
